info.codeblock:
/* TaskFlow Documentation Branding */

/* Callout boxes for notes */
.callout {
  padding: 1rem 1.25rem;
  margin: 1rem 0;
  border-left: 4px solid #ccc;
  border-radius: 4px;
  background: #f8f9fa;
}

.callout-note {
  border-left-color: #0d6efd;
  background: #e8f0fe;
}

.callout-tip {
  border-left-color: #198754;
  background: #e8f5e9;
}

.callout-warning {
  border-left-color: #fd7e14;
  background: #fff3e0;
}

.callout-caution {
  border-left-color: #dc3545;
  background: #fde8e8;
}

.callout-important {
  border-left-color: #6f42c1;
  background: #f3e8fd;
}

/* Step styling */
.taskbody ol > li {
  margin-bottom: 0.75rem;
  line-height: 1.6;
}

/* Code blocks */
pre.codeblock {
  background: #1e1e1e;
  color: #d4d4d4;
  padding: 1rem;
  border-radius: 6px;
  overflow-x: auto;
  font-size: 0.9rem;
}
